"use client";

import * as React from "react";
import {
  IconClock,
  IconCoin,
  IconChartBar,
  IconAlertTriangle,
  IconCalendarStats,
  IconChevronRight,
  IconCheck,
  IconUserExclamation,
  IconCoffee,
} from "@tabler/icons-react";
import {
  Container,
  StatGroup,
  Meter,
  Progress,
  ScheduleGrid,
  type ScheduleCell,
  type ScheduleCellTone,
  PersonCell,
  Badge,
  type BadgeProps,
  Tag,
  Button,
  Separator,
  MetadataList,
  Alert,
  AlertTitle,
  AlertDescription,
  Tabs,
  TabsList,
  TabsTrigger,
  TabsContent,
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
  formatCurrency,
  formatPercent,
} from "@gunjo/ui";
import {
  STAFF,
  WEEK_DATES,
  BANDS,
  type Staff,
  type DayShift,
  type Role,
  bandWeekTotals,
  staffWeekHours,
  staffWeekWage,
  staffedCount,
  shiftStats,
  shortfalls,
  TOTAL_HOURS,
  TOTAL_LABOR,
  LABOR_RATE,
  TARGET_LABOR_RATE,
  PLANNED_SALES,
} from "./data";

// ── 役割 → Badge 色 ──────────────────────────────────────────────
type BadgeVariant = NonNullable<BadgeProps["variant"]>;
const ROLE_BADGE: Record<Role, BadgeVariant> = {
  ホール: "info",
  キッチン: "warning",
  レジ: "secondary",
  洗い場: "outline",
};

// ── シフト種別 → セルのトーン ─────────────────────────────────────
function cellTone(d: DayShift): ScheduleCellTone {
  if (!d.confirmed) return "warning"; // 未確定
  if (d.kind === "通し") return "primary";
  return "default";
}

function timeLabel(d: DayShift): string {
  if (d.kind === "休" || !d.start) return "休";
  return `${d.start}–${d.end}`;
}

const fmtH = (h: number) => `${h.toFixed(1)}h`;

export default function RestaurantShiftsPage() {
  const [selected, setSelected] = React.useState<Staff | null>(null);
  const open = selected != null;

  const stats = React.useMemo(() => shiftStats(), []);
  const gaps = React.useMemo(() => shortfalls(), []);

  // ── 週次シフト表 (スタッフ × 曜日) ────────────────────────────
  const rows = STAFF.map((st) => ({
    id: st.id,
    label: (
      <span className="block max-w-[88px] truncate text-left text-[13px] font-semibold leading-tight">
        {st.name}
      </span>
    ),
    sublabel: st.role,
    ariaLabel: `${st.name}（${st.role}・${st.employment}）`,
  }));

  const columns = WEEK_DATES.map((d) => ({
    id: d.id,
    label: d.label,
    sublabel: d.date,
    ariaLabel: `${d.label}曜 ${d.date}`,
  }));

  const cells: ScheduleCell[] = [];
  STAFF.forEach((st) => {
    st.week.forEach((d, di) => {
      const col = WEEK_DATES[di];
      if (!d || d.kind === "休") {
        cells.push({
          rowId: st.id,
          colId: col.id,
          tone: "muted",
          content: <span className="text-[11px] text-muted-foreground">休</span>,
          description: `${st.name} 休み`,
          onSelect: () => setSelected(st),
        });
        return;
      }
      cells.push({
        rowId: st.id,
        colId: col.id,
        tone: cellTone(d),
        onSelect: () => setSelected(st),
        description: `${timeLabel(d)} ${d.role} ${d.kind}${
          d.confirmed ? "" : " 未確定"
        }`,
        content: (
          <div className="flex flex-col gap-0.5">
            <span className="text-[12px] font-semibold tabular-nums leading-tight">
              {timeLabel(d)}
            </span>
            <span className="flex items-center gap-1 text-[10px] text-muted-foreground">
              <span>{d.kind}</span>
              {!d.confirmed && (
                <span className="font-semibold text-warning">希望</span>
              )}
            </span>
          </div>
        ),
      });
    });
  });

  // ── サマリーメトリクス ────────────────────────────────────────
  const summary = [
    {
      label: "週 総労働時間",
      value: fmtH(TOTAL_HOURS),
      hint: `スタッフ ${STAFF.length}名`,
    },
    {
      label: "週 人件費",
      value: formatCurrency(TOTAL_LABOR),
      hint: `想定売上 ${formatCurrency(PLANNED_SALES, { compact: true })}`,
    },
    {
      label: "人件費率",
      value: formatPercent(LABOR_RATE, { maximumFractionDigits: 1 }),
      change: `目標 ${formatPercent(TARGET_LABOR_RATE, { maximumFractionDigits: 0 })}`,
      trend: (LABOR_RATE > TARGET_LABOR_RATE ? "up" : "down") as "up" | "down",
      tone: (LABOR_RATE > TARGET_LABOR_RATE ? "negative" : "positive") as
        | "negative"
        | "positive",
    },
    {
      label: "確定率",
      value: formatPercent(stats.confirmRate, { maximumFractionDigits: 0 }),
      hint: `${stats.total - stats.confirmed}件 未確定`,
    },
  ];

  return (
    <main className="min-h-full bg-background py-6">
      <Container size="2xl" className="space-y-6">
        {/* ── ヘッダ ── */}
        <header className="flex flex-col gap-3 sm:flex-row sm:items-end sm:justify-between">
          <div className="space-y-1">
            <div className="flex items-center gap-2 text-xs text-muted-foreground">
              <IconCalendarStats className="h-4 w-4" />
              <span>シフト管理</span>
            </div>
            <h1 className="text-xl font-bold tracking-tight sm:text-2xl">
              週次シフト表
            </h1>
            <p className="text-sm text-muted-foreground">
              炭火 串吉（くしきち）渋谷店 ・ 6/22(月)〜6/28(日)
            </p>
          </div>
          <div className="flex items-center gap-2">
            <Button variant="outline" size="sm">
              前の週
            </Button>
            <Button variant="outline" size="sm">
              次の週
            </Button>
            <Button size="sm">シフトを確定</Button>
          </div>
        </header>

        {/* ── サマリーメトリクス ── */}
        <StatGroup items={summary} cols={{ base: 2, md: 4 }} />

        {/* ── 欠員アラート ── */}
        {gaps.length > 0 && (
          <Alert variant="warning">
            <IconAlertTriangle className="h-4 w-4" />
            <AlertTitle>人員が不足している時間帯があります</AlertTitle>
            <AlertDescription>
              <div className="mt-1 flex flex-wrap gap-1.5">
                {gaps.map((g, i) => (
                  <Tag key={i} variant="destructive" size="sm">
                    {WEEK_DATES[g.dayIndex].label} {g.band.label}{" "}
                    <span className="tabular-nums">
                      {g.staffed}/{g.band.required}
                    </span>
                    （−{g.gap}）
                  </Tag>
                ))}
              </div>
            </AlertDescription>
          </Alert>
        )}

        {/* ── メイン: タブ ── */}
        <Tabs defaultValue="grid" className="border-0">
          <TabsList>
            <TabsTrigger value="grid">週次シフト表</TabsTrigger>
            <TabsTrigger value="coverage">人員過不足</TabsTrigger>
            <TabsTrigger value="labor">人件費</TabsTrigger>
          </TabsList>

          {/* ── 週次シフト表 ── */}
          <TabsContent value="grid" className="px-0">
            <Card>
              <CardHeader className="flex-row items-center justify-between gap-2 space-y-0">
                <div>
                  <CardTitle className="text-base">
                    スタッフ × 曜日
                  </CardTitle>
                  <CardDescription>
                    セルを選ぶと個別シフトを確認できます。黄色は希望のみ（未確定）。
                  </CardDescription>
                </div>
                <div className="hidden shrink-0 items-center gap-3 text-[11px] text-muted-foreground sm:flex">
                  <span className="inline-flex items-center gap-1">
                    <span className="inline-block h-2.5 w-2.5 rounded-sm bg-primary/30 ring-1 ring-primary/40" />
                    通し
                  </span>
                  <span className="inline-flex items-center gap-1">
                    <span className="inline-block h-2.5 w-2.5 rounded-sm bg-warning-subtle ring-1 ring-warning-border" />
                    未確定
                  </span>
                </div>
              </CardHeader>
              <CardContent>
                <ScheduleGrid
                  label="週次シフト表（スタッフ × 曜日）"
                  cornerLabel="スタッフ"
                  rows={rows}
                  columns={columns}
                  cells={cells}
                  rowHeaderWidth={96}
                  minColumnWidth={92}
                />
              </CardContent>
            </Card>
          </TabsContent>

          {/* ── 人員過不足 ── */}
          <TabsContent value="coverage" className="px-0">
            <div className="grid gap-4 md:grid-cols-3">
              {BANDS.map((band) => {
                const { required, staffed } = bandWeekTotals(band.id);
                const over = staffed >= required;
                return (
                  <Card key={band.id}>
                    <CardHeader className="space-y-1 pb-3">
                      <div className="flex items-center justify-between">
                        <CardTitle className="text-base">{band.label}</CardTitle>
                        <Badge variant={over ? "success" : "destructive"}>
                          {over ? "充足" : `欠員 ${required - staffed}`}
                        </Badge>
                      </div>
                      <CardDescription>{band.time} ・ 週合計</CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-3">
                      <Meter
                        label={`${band.label} 配置`}
                        value={staffed}
                        max={required}
                        direction="fill-is-good"
                        unit="人"
                        formatValue={(v) => `${Math.round(v)}人`}
                      />
                      <div className="flex items-baseline justify-between text-sm">
                        <span className="text-muted-foreground">配置 / 必要</span>
                        <span className="font-semibold tabular-nums">
                          {staffed} / {required} 人・日
                        </span>
                      </div>
                      <Separator />
                      <div className="space-y-1.5">
                        <p className="text-xs font-medium text-muted-foreground">
                          日別の配置
                        </p>
                        <div className="grid grid-cols-7 gap-1">
                          {WEEK_DATES.map((d, di) => {
                            const c = staffedCount(di, band.id);
                            const short = c < band.required;
                            return (
                              <div
                                key={d.id}
                                className="flex flex-col items-center gap-0.5"
                                title={`${d.label} ${band.label}: ${c}/${band.required}人`}
                              >
                                <span className="text-[10px] text-muted-foreground">
                                  {d.label}
                                </span>
                                <span
                                  className={
                                    "flex h-6 w-full items-center justify-center rounded text-[11px] font-semibold tabular-nums " +
                                    (short
                                      ? "bg-destructive-subtle text-destructive"
                                      : "bg-success-subtle text-success-strong")
                                  }
                                >
                                  {c}
                                </span>
                              </div>
                            );
                          })}
                        </div>
                      </div>
                    </CardContent>
                  </Card>
                );
              })}
            </div>
          </TabsContent>

          {/* ── 人件費 ── */}
          <TabsContent value="labor" className="px-0">
            <div className="grid gap-4 lg:grid-cols-3">
              <Card className="lg:col-span-1">
                <CardHeader>
                  <CardTitle className="text-base">人件費率</CardTitle>
                  <CardDescription>対 想定売上</CardDescription>
                </CardHeader>
                <CardContent className="space-y-4">
                  <div>
                    <p className="text-3xl font-bold tabular-nums">
                      {formatPercent(LABOR_RATE, { maximumFractionDigits: 1 })}
                    </p>
                    <p className="text-xs text-muted-foreground">
                      目標 {formatPercent(TARGET_LABOR_RATE, { maximumFractionDigits: 0 })} 以内
                    </p>
                  </div>
                  <Meter
                    label="人件費率（目標30%）"
                    value={Math.round(LABOR_RATE * 1000)}
                    max={1000}
                    target={Math.round(TARGET_LABOR_RATE * 1000)}
                    direction="higher-is-worse"
                    thresholds={{ warning: 0.9, over: 1 }}
                    formatValue={(v) =>
                      formatPercent(v / 1000, { maximumFractionDigits: 1 })
                    }
                  />
                  <MetadataList
                    items={[
                      { label: "週 総労働時間", value: fmtH(TOTAL_HOURS) },
                      { label: "週 人件費", value: formatCurrency(TOTAL_LABOR) },
                      {
                        label: "想定売上",
                        value: formatCurrency(PLANNED_SALES),
                      },
                    ]}
                  />
                </CardContent>
              </Card>

              <Card className="lg:col-span-2">
                <CardHeader>
                  <CardTitle className="text-base">スタッフ別 労働時間・賃金</CardTitle>
                  <CardDescription>今週の確定＋希望分を含む</CardDescription>
                </CardHeader>
                <CardContent className="space-y-3">
                  {[...STAFF]
                    .map((st) => ({
                      st,
                      h: staffWeekHours(st),
                      w: staffWeekWage(st),
                    }))
                    .sort((a, b) => b.h - a.h)
                    .map(({ st, h, w }) => (
                      <button
                        key={st.id}
                        type="button"
                        onClick={() => setSelected(st)}
                        className="flex w-full items-center gap-3 rounded-lg border border-border bg-card p-2.5 text-left transition-colors hover:border-ring/60 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
                      >
                        <PersonCell
                          className="flex-1"
                          size="sm"
                          name={st.name}
                          secondary={`${st.role} ・ ${st.employment}`}
                          avatarClassName="bg-primary/10 text-primary"
                          trailing={
                            <Badge variant={ROLE_BADGE[st.role]}>{st.role}</Badge>
                          }
                        />
                        <div className="hidden w-40 shrink-0 sm:block">
                          <Progress
                            value={h}
                            max={Math.max(...STAFF.map(staffWeekHours))}
                            label={`${st.name} 労働時間`}
                            valueText={`${fmtH(h)} / 賃金 ${formatCurrency(w)}`}
                          />
                        </div>
                        <div className="w-20 shrink-0 text-right">
                          <p className="text-sm font-semibold tabular-nums">
                            {fmtH(h)}
                          </p>
                          <p className="text-[11px] text-muted-foreground tabular-nums">
                            {formatCurrency(w, { compact: true })}
                          </p>
                        </div>
                      </button>
                    ))}
                </CardContent>
              </Card>
            </div>
          </TabsContent>
        </Tabs>
      </Container>

      {/* ── スタッフ個別ドリルイン ── */}
      <Sheet open={open} onOpenChange={(o) => !o && setSelected(null)}>
        <SheetContent
          side="right"
          className="w-full overflow-y-auto sm:max-w-md"
        >
          {selected && (
            <StaffDetail staff={selected} />
          )}
        </SheetContent>
      </Sheet>
    </main>
  );
}

function StaffDetail({ staff }: { staff: Staff }) {
  const h = staffWeekHours(staff);
  const w = staffWeekWage(staff);
  const longRun = staff.consecutiveDays >= 5;

  return (
    <div className="space-y-5">
      <SheetHeader className="space-y-0 text-left">
        <SheetTitle className="sr-only">{staff.name} の個別シフト</SheetTitle>
        <SheetDescription className="sr-only">
          {staff.name}（{staff.role}・{staff.employment}）の週シフト・希望・労働時間
        </SheetDescription>
        <PersonCell
          size="lg"
          name={staff.name}
          secondary={staff.kana}
          tertiary={`${staff.role} ・ ${staff.employment} ・ 時給 ${formatCurrency(
            staff.wage
          )}`}
          avatarClassName="bg-primary/10 text-primary"
          trailing={<Badge variant={ROLE_BADGE[staff.role]}>{staff.role}</Badge>}
        />
      </SheetHeader>

      {longRun && (
        <Alert variant="warning">
          <IconUserExclamation className="h-4 w-4" />
          <AlertTitle>連勤に注意</AlertTitle>
          <AlertDescription>
            今週は {staff.consecutiveDays} 連勤の予定です。休憩・公休の確保を検討してください。
          </AlertDescription>
        </Alert>
      )}

      <div className="grid grid-cols-2 gap-3">
        <Card className="p-3">
          <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
            <IconClock className="h-3.5 w-3.5" /> 今週の労働時間
          </div>
          <p className="mt-1 text-xl font-bold tabular-nums">{fmtH(h)}</p>
        </Card>
        <Card className="p-3">
          <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
            <IconCoin className="h-3.5 w-3.5" /> 今週の賃金
          </div>
          <p className="mt-1 text-xl font-bold tabular-nums">
            {formatCurrency(w)}
          </p>
        </Card>
      </div>

      <section className="space-y-2">
        <h3 className="flex items-center gap-1.5 text-sm font-semibold">
          <IconChartBar className="h-4 w-4" /> 週シフト
        </h3>
        <ul className="space-y-1.5">
          {staff.week.map((d, di) => {
            const date = WEEK_DATES[di];
            const off = !d || d.kind === "休";
            return (
              <li
                key={date.id}
                className="flex items-center gap-3 rounded-md border border-border/70 bg-card px-3 py-2"
              >
                <span className="w-10 shrink-0 text-sm font-semibold">
                  {date.label}{" "}
                  <span className="text-[11px] font-normal text-muted-foreground">
                    {date.date}
                  </span>
                </span>
                {off ? (
                  <span className="text-sm text-muted-foreground">休み</span>
                ) : (
                  <>
                    <span className="flex-1 text-sm font-medium tabular-nums">
                      {d!.start}–{d!.end}
                    </span>
                    <Tag variant="outline" size="sm">
                      {d!.kind}
                    </Tag>
                    {d!.breakMin > 0 && (
                      <span className="inline-flex items-center gap-0.5 text-[11px] text-muted-foreground">
                        <IconCoffee className="h-3 w-3" />
                        {d!.breakMin}分
                      </span>
                    )}
                    {d!.confirmed ? (
                      <Badge variant="success">
                        <IconCheck className="h-3 w-3" /> 確定
                      </Badge>
                    ) : (
                      <Badge variant="warning">希望</Badge>
                    )}
                  </>
                )}
              </li>
            );
          })}
        </ul>
      </section>

      <Separator />

      <section className="space-y-1.5">
        <h3 className="text-sm font-semibold">希望シフト・メモ</h3>
        <p className="rounded-md bg-muted/50 p-3 text-sm text-muted-foreground">
          {staff.requestNote}
        </p>
      </section>

      <div className="flex gap-2">
        <Button className="flex-1">このスタッフのシフトを確定</Button>
        <Button variant="outline">編集</Button>
      </div>
    </div>
  );
}

// 飲食店 週次シフト管理 — ドメインデータ（サーバー安全 / 関数 prop なし）
// 店舗: 居酒屋「炭火 串吉（くしきち）」渋谷店  / 2026-06-22(月)〜06-28(日) の週

export type Role = "ホール" | "キッチン" | "レジ" | "洗い場";
export type Employment = "社員" | "アルバイト";
export type Band = "lunch" | "idle" | "dinner";

export interface DayShift {
  /** 時間帯ラベル。休 のときは null */
  start: string | null; // "10:00"
  end: string | null; // "15:00"
  role: Role;
  /** 早番 / 遅番 / 通し / 休 */
  kind: "早番" | "遅番" | "通し" | "休";
  /** スタッフが出した希望どおりか */
  matchesRequest: boolean;
  /** 確定済みか（false = 希望のみ・未確定） */
  confirmed: boolean;
  /** 休憩(分)。通しは60、それ以外45 など */
  breakMin: number;
}

export interface Staff {
  id: string;
  name: string;
  kana: string;
  role: Role;
  employment: Employment;
  /** 時給 (円) */
  wage: number;
  /** 曜日インデックス 0=月 … 6=日 のシフト */
  week: (DayShift | null)[];
  /** 今週の希望提出メモ */
  requestNote: string;
  /** 連勤数（注意喚起用） */
  consecutiveDays: number;
}

export const WEEK_DATES = [
  { id: "mon", label: "月", date: "6/22" },
  { id: "tue", label: "火", date: "6/23" },
  { id: "wed", label: "水", date: "6/24" },
  { id: "thu", label: "木", date: "6/25" },
  { id: "fri", label: "金", date: "6/26", emphasis: true },
  { id: "sat", label: "土", date: "6/27", emphasis: true },
  { id: "sun", label: "日", date: "6/28", emphasis: true },
] as const;

const off = (): DayShift => ({
  start: null,
  end: null,
  role: "ホール",
  kind: "休",
  matchesRequest: true,
  confirmed: true,
  breakMin: 0,
});

const s = (
  start: string,
  end: string,
  role: Role,
  kind: DayShift["kind"],
  opts: Partial<DayShift> = {}
): DayShift => ({
  start,
  end,
  role,
  kind,
  matchesRequest: opts.matchesRequest ?? true,
  confirmed: opts.confirmed ?? true,
  breakMin: opts.breakMin ?? (kind === "通し" ? 90 : 45),
});

export const STAFF: Staff[] = [
  {
    id: "s1",
    name: "田中 美咲",
    kana: "たなか みさき",
    role: "ホール",
    employment: "社員",
    wage: 1450,
    consecutiveDays: 5,
    requestNote: "土日は通しで入れます。木曜は大学の予定で休み希望。",
    week: [
      s("10:00", "20:00", "ホール", "通し"),
      s("17:00", "23:00", "ホール", "遅番"),
      s("10:00", "20:00", "ホール", "通し"),
      off(),
      s("17:00", "23:00", "ホール", "遅番"),
      s("10:00", "22:00", "ホール", "通し", { breakMin: 90 }),
      s("10:00", "22:00", "ホール", "通し", { breakMin: 90 }),
    ],
  },
  {
    id: "s2",
    name: "佐藤 健",
    kana: "さとう けん",
    role: "キッチン",
    employment: "社員",
    wage: 1600,
    consecutiveDays: 6,
    requestNote: "週6で入れます。仕込みがあるので早番中心希望。",
