// ───────────────────────── 時間帯ごとの必要人数 ─────────────────────────
export interface BandSpec {
  id: Band;
  label: string;
  time: string;
  /** 各日の必要人数（必要配置の目安） */
  required: number;
}

export const BANDS: BandSpec[] = [
  { id: "lunch", label: "ランチ", time: "11:00–15:00", required: 4 },
  { id: "idle", label: "アイドル", time: "15:00–17:00", required: 2 },
  { id: "dinner", label: "ディナー", time: "17:00–23:00", required: 6 },
];

/** ある日のある時間帯に「配置されている」人数を数える（簡易：時間重なり判定） */
function bandHours(band: Band): [number, number] {
  if (band === "lunch") return [11, 15];
  if (band === "idle") return [15, 17];
  return [17, 23];
}
function toH(t: string): number {
  const [h] = t.split(":");
  return Number(h);
}
export function staffedCount(dayIndex: number, band: Band): number {
  const [bs, be] = bandHours(band);
  return STAFF.reduce((n, st) => {
    const d = st.week[dayIndex];
    if (!d || d.kind === "休" || !d.start || !d.end) return n;
    const ds = toH(d.start);
    const de = toH(d.end);
    // 重なりがあれば1人としてカウント（簡易）
    return ds < be && de > bs ? n + 1 : n;
  }, 0);
}

/** 週合計の必要 vs 配置（バンド別、全曜日合算） */
export function bandWeekTotals(band: Band) {
  const spec = BANDS.find((b) => b.id === band)!;
  let staffed = 0;
  for (let d = 0; d < 7; d++) staffed += staffedCount(d, band);
  const required = spec.required * 7;
  return { required, staffed, spec };
}

// ───────────────────────── 人件費計算 ─────────────────────────
function shiftMinutes(d: DayShift): number {
  if (!d.start || !d.end || d.kind === "休") return 0;
  const [sh, sm] = d.start.split(":").map(Number);
  const [eh, em] = d.end.split(":").map(Number);
  return eh * 60 + em - (sh * 60 + sm) - d.breakMin;
}
export function staffWeekHours(st: Staff): number {
  return st.week.reduce((sum, d) => sum + (d ? shiftMinutes(d) : 0), 0) / 60;
}
export function staffWeekWage(st: Staff): number {
  return Math.round(staffWeekHours(st) * st.wage);
}

export const TOTAL_HOURS = STAFF.reduce((s, st) => s + staffWeekHours(st), 0);
export const TOTAL_LABOR = STAFF.reduce((s, st) => s + staffWeekWage(st), 0);
/** 想定売上（週） */
export const PLANNED_SALES = 2_650_000;
export const LABOR_RATE = TOTAL_LABOR / PLANNED_SALES; // 人件費率
export const TARGET_LABOR_RATE = 0.3; // 目標 30%

/** 確定率・希望未反映 */
export function shiftStats() {
  let total = 0;
  let confirmed = 0;
  let unfilledRequest = 0;
  for (const st of STAFF) {
    for (const d of st.week) {
      if (!d || d.kind === "休") continue;
      total++;
      if (d.confirmed) confirmed++;
      if (!d.matchesRequest) unfilledRequest++;
    }
  }
  return { total, confirmed, confirmRate: confirmed / total, unfilledRequest };
}

/** 欠員のある (曜日 × 時間帯) を列挙 */
export function shortfalls() {
  const out: { dayIndex: number; band: BandSpec; staffed: number; gap: number }[] = [];
  for (let d = 0; d < 7; d++) {
    for (const band of BANDS) {
      const staffed = staffedCount(d, band.id);
      if (staffed < band.required) {
        out.push({ dayIndex: d, band, staffed, gap: band.required - staffed });
      }
    }
  }
  return out;
}
